// Usamos a sintaxe correta do n8n para acessar o conteúdo da mensagem recebida
const valorProcurado = $('Edit Fields').first().json.body.conversation.messages[0].content; 

// 2. Pega todos os itens retornados pelo Supabase (input deste nó)
const itensSupabase = items;

// 3. Função para limpar o texto (evita erros com espaços ou maiúsculas)
function limpar(texto) {
  if (!texto) return "";
  return texto.toString().trim().toLowerCase();
}

const valorLimpo = limpar(valorProcurado);

// 4. Verifica se ALGUM item da lista tem o conteúdo igual
const encontrou = itensSupabase.some(item => {
  const conteudoBanco = limpar(item.json.content);
  return conteudoBanco === valorLimpo;
});

// 5. Retorna o resultado para o próximo nó (geralmente um IF)
return {
  json: {
    encontrou_duplicidade: encontrou,
    valor_buscado: valorProcurado,
    total_itens_verificados: itensSupabase.length
  }
};

